import { api } from './client';

export interface Incident {
  id: string;
  incident_number: string;
  client_id: string;
  client_name?: string | null;
  title: string;
  description?: string;
  status: string;
  priority: string;
  received_at: string;
  due_at?: string;
  object_id?: string | null;
  unit_id?: string | null;
  object_name?: string | null;
  unit_serial?: string | null;
  unit_type?: string | null;
  unit_model?: string | null;
  asset_type_name?: string | null;
  assigned_to?: string | null;
  assigned_user_name?: string | null;
  asset_component_id?: string | null;
  asset_component_name?: string | null;
  unread_count?: number;
  resolution?: string | null;
  completed_at?: string | null;
}

export interface IncidentActivityEntry {
  id: string;
  incident_id: string;
  action: 'created' | 'status_changed' | 'assigned' | 'completion_signed' | 'act_generated';
  description: string;
  actor_user_id?: string | null;
  actor_name?: string | null;
  metadata?: Record<string, unknown> | null;
  created_at: string;
}

export interface PaginatedResponse<T> {
  data: T[];
  pagination: {
    page: number;
    limit: number;
    total: number;
    totalPages: number;
  };
}

export const incidentsApi = {
  list: (params?: Record<string, string>) => {
    const query = params ? `?${new URLSearchParams(params)}` : '';
    return api.get<PaginatedResponse<Incident>>(`/incidents${query}`);
  },

  get: (id: string) =>
    api.get<{ data: Incident }>(`/incidents/${id}`),

  listActivity: (id: string) =>
    api.get<{ data: IncidentActivityEntry[] }>(`/incidents/${id}/activity`),

  create: (data: Partial<Incident>) =>
    api.post<{ data: Incident }>('/incidents', data),

  updateStatus: (id: string, status: string, resolution?: string) =>
    api.patch<{ data: Incident }>(`/incidents/${id}/status`, { status, resolution }),

  assign: (id: string, assignedTo: string) =>
    api.patch<{ data: Incident }>(`/incidents/${id}/assign`, { assigned_to: assignedTo }),

  update: (id: string, data: { asset_component_id?: string | null }) =>
    api.patch<{ data: Incident }>(`/incidents/${id}`, data),
};
